"use client";

import { useRef, useMemo, useEffect } from "react";
import { useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { particleProfiles } from "@/data/projects";
import type { Domain } from "@/data/projects";

interface ParticleFieldProps {
  domain?: Domain | null;
  morphProgress?: number; // 0 = previous domain, 1 = current domain
}

const PARTICLE_COUNT = 5000;

// ─── Behaviour: Rippl — concentric rings emanating from points ───
function getRipplPositions(count: number, time: number): Float32Array {
  const pos = new Float32Array(count * 3);
  const rings = 12;
  for (let i = 0; i < count; i++) {
    const ring = Math.floor(i / (count / rings));
    const angle = (i / (count / rings)) * Math.PI * 2;
    const radius = (ring + 1) * 0.8 + Math.sin(time * 0.5 + ring * 0.4) * 0.3;
    const scatter = (Math.random() - 0.5) * 0.4;
    pos[i * 3] = Math.cos(angle) * radius + scatter;
    pos[i * 3 + 1] = (Math.random() - 0.5) * 0.5;
    pos[i * 3 + 2] = Math.sin(angle) * radius + scatter;
  }
  return pos;
}

// ─── Behaviour: Realm — organic swarm / butterfly silhouette ───
function getRealmPositions(count: number, time: number): Float32Array {
  const pos = new Float32Array(count * 3);
  for (let i = 0; i < count; i++) {
    const t = i / count;
    // Butterfly wing parametric (simplified)
    const angle = t * Math.PI * 4;
    const r = Math.pow(Math.abs(Math.cos(angle * 2)), 0.5) * 3 + Math.sin(time * 0.3 + i * 0.001) * 0.5;
    const drift = Math.sin(time * 0.2 + i * 0.002) * 0.8;
    pos[i * 3] = Math.cos(angle) * r + drift;
    pos[i * 3 + 1] = Math.sin(angle) * r * 0.6 + Math.sin(time * 0.4 + i * 0.003) * 0.3;
    pos[i * 3 + 2] = Math.sin(i * 0.1) * 2 + drift * 0.5;
  }
  return pos;
}

// ─── Behaviour: Trmeric — structured data lattice ───
function getTrmericPositions(count: number, time: number): Float32Array {
  const pos = new Float32Array(count * 3);
  const gridSize = Math.ceil(Math.cbrt(count));
  for (let i = 0; i < count; i++) {
    const x = (i % gridSize) - gridSize / 2;
    const y = (Math.floor(i / gridSize) % gridSize) - gridSize / 2;
    const z = Math.floor(i / (gridSize * gridSize)) - gridSize / 2;
    const flow = Math.sin(time * 0.6 + x * 0.5 + y * 0.3) * 0.15;
    pos[i * 3] = x * 0.6 + flow;
    pos[i * 3 + 1] = y * 0.6 + flow;
    pos[i * 3 + 2] = z * 0.6;
  }
  return pos;
}

function getIdlePositions(count: number, time: number): Float32Array {
  const pos = new Float32Array(count * 3);
  for (let i = 0; i < count; i++) {
    const theta = (i / count) * Math.PI * 2;
    const phi = Math.acos(2 * (i / count) - 1);
    const r = 4 + Math.sin(time * 0.2 + i * 0.01) * 0.5;
    pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta) * 0.5;
    pos[i * 3 + 2] = r * Math.cos(phi);
  }
  return pos;
}

function getDomainColor(domain: Domain | null): THREE.Color {
  if (domain === "rippl") return new THREE.Color("#78B9C5");
  if (domain === "realm") return new THREE.Color("#4A9E8E");
  if (domain === "trmeric") return new THREE.Color("#FFA426");
  return new THREE.Color("#6B6157");
}

export default function ParticleField({ domain = null, morphProgress = 1 }: ParticleFieldProps) {
  const points = useRef<THREE.Points>(null!);
  const geometry = useRef<THREE.BufferGeometry>(null!);
  const timeRef = useRef(0);
  const prevDomainRef = useRef<Domain | null>(null);

  const { size } = useThree();

  const initialPositions = useMemo(() => {
    const pos = new Float32Array(PARTICLE_COUNT * 3);
    for (let i = 0; i < PARTICLE_COUNT; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 8;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 4;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 6;
    }
    return pos;
  }, []);

  useEffect(() => {
    prevDomainRef.current = domain;
  }, [domain]);

  useFrame((state, delta) => {
    timeRef.current += delta;
    const t = timeRef.current;

    if (!geometry.current) return;

    const targetPos = domain === "rippl"
      ? getRipplPositions(PARTICLE_COUNT, t)
      : domain === "realm"
      ? getRealmPositions(PARTICLE_COUNT, t)
      : domain === "trmeric"
      ? getTrmericPositions(PARTICLE_COUNT, t)
      : getIdlePositions(PARTICLE_COUNT, t);

    const currentAttr = geometry.current.attributes.position as THREE.BufferAttribute;
    const current = currentAttr.array as Float32Array;

    // Smooth lerp toward target
    const lerpSpeed = 0.03;
    for (let i = 0; i < PARTICLE_COUNT * 3; i++) {
      current[i] += (targetPos[i] - current[i]) * lerpSpeed;
    }
    currentAttr.needsUpdate = true;

    // Gentle rotation
    if (points.current) {
      points.current.rotation.y += delta * 0.04;
      points.current.rotation.x = Math.sin(t * 0.1) * 0.05;
    }

    // Color pulse
    const mat = points.current?.material as THREE.PointsMaterial;
    if (mat) {
      const target = getDomainColor(domain);
      mat.color.lerp(target, 0.02);
      mat.opacity = 0.6 + Math.sin(t * 0.5) * 0.1;
    }
  });

  return (
    <points ref={points}>
      <bufferGeometry ref={geometry}>
        <bufferAttribute
          attach="attributes-position"
          args={[initialPositions, 3]}
          count={PARTICLE_COUNT}
        />
      </bufferGeometry>
      <pointsMaterial
        size={size.width < 768 ? 0.018 : 0.012}
        color={getDomainColor(domain)}
        transparent
        opacity={0.6}
        sizeAttenuation
        depthWrite={false}
      />
    </points>
  );
}
